SET
  @Name_27e6903b = N'ExternalChangeDetection_DetectCreations'
SET
  @CategoryID_27e6903b = 'FE1AE5B2-FC57-43B2-B560-A673713E1679'
SET
  @Description_27e6903b = N'Detects new records created in an external system by comparing base view rows to existing MJ record changes.'
SET
  @SQL_27e6903b = N'-- T-SQL variant for External Change Detection - Detect Creations
SELECT
    ot.*, ot.[{{ CreatedAtField }}] AS __ecd_CreatedAt, ot.[{{ UpdatedAtField }}] AS __ecd_UpdatedAt
FROM
    [{{ SchemaName }}].[{{ BaseView }}] ot
LEFT JOIN
    ${flyway:defaultSchema}.vwRecordChanges rc
    ON
    ({{ PrimaryKeyJoin }} = rc.RecordID) AND
    rc.Type = ''Create'' AND
    rc.EntityID = {{ EntityID | sqlString }}
WHERE
    rc.RecordID IS NULL
ORDER BY
    {{ PrimaryKeyOrderBy }}
'
