DECLARE @Name_df156de4 NVARCHAR(255),
@CategoryID_df156de4 UNIQUEIDENTIFIER,
@UserQuestion_df156de4 NVARCHAR(MAX),
@Description_df156de4 NVARCHAR(MAX),
@SQL_df156de4 NVARCHAR(MAX),
@TechnicalDescription_df156de4 NVARCHAR(MAX),
@OriginalSQL_df156de4 NVARCHAR(MAX),
@Feedback_df156de4 NVARCHAR(MAX),
@Status_df156de4 NVARCHAR(15),
@QualityRank_df156de4 INT,
@ExecutionCostRank_df156de4 INT,
@UsesTemplate_df156de4 BIT,
@AuditQueryRuns_df156de4 BIT,
@CacheEnabled_df156de4 BIT,
@CacheTTLMinutes_df156de4 INT,
@CacheMaxSize_df156de4 INT,
@EmbeddingVector_df156de4 NVARCHAR(MAX),
@EmbeddingModelID_df156de4 UNIQUEIDENTIFIER,
@CacheValidationSQL_df156de4 NVARCHAR(MAX),
@SQLDialectID_df156de4 UNIQUEIDENTIFIER,
