SET
  @Name_df156de4 = N'ExternalChangeDetection_DetectUpdates'
SET
  @CategoryID_df156de4 = 'FE1AE5B2-FC57-43B2-B560-A673713E1679'
SET
  @Description_df156de4 = N'Detects updated records in an external system by comparing UpdatedAt timestamps.'
SET
  @SQL_df156de4 = N'-- T-SQL variant for External Change Detection - Detect Updates
SELECT
    ot.*, ot.[{{ UpdatedAtField }}] AS __ecd_UpdatedAt, rc.last_change_time __ecd_LatestRecordChangeAt
FROM
    [{{ SchemaName }}].[{{ BaseView }}] ot
INNER JOIN (
    SELECT
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM
        ${flyway:defaultSchema}.vwRecordChanges
    WHERE
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc.RecordID
WHERE
    ot.[{{ UpdatedAtField }}] > COALESCE(rc.last_change_time, ''1900-01-01 00:00:00.000'')
ORDER BY
    {{ PrimaryKeyOrderBy }}
'
SET
  @Status_df156de4 = N'Approved'
SET
  @QualityRank_df156de4 = 0
SET
  @UsesTemplate_df156de4 = 1
SET
  @AuditQueryRuns_df156de4 = 0
SET
