-- Save MJ: Query SQLs (core SP call only)
DECLARE @QueryID_0e930e55 UNIQUEIDENTIFIER,
@SQLDialectID_0e930e55 UNIQUEIDENTIFIER,
@SQL_0e930e55 NVARCHAR(MAX),
@ID_0e930e55 UNIQUEIDENTIFIER
SET
  @QueryID_0e930e55 = '3366D42B-C3A1-4CE0-9F40-7FBE15F2EA57'
SET
  @SQLDialectID_0e930e55 = '426915F2-D4FE-4AB9-97A8-39063561DE9F'
SET
  @SQL_0e930e55 = N'-- PostgreSQL variant for External Change Detection - Detect Creations
SELECT
    ot.*, ot."{{ CreatedAtField }}" AS "__ecd_CreatedAt", ot."{{ UpdatedAtField }}" AS "__ecd_UpdatedAt"
FROM
    "{{ SchemaName }}"."{{ BaseView }}" ot
LEFT JOIN
    ${flyway:defaultSchema}.vwRecordChanges rc
    ON
    ({{ PrimaryKeyJoin }} = rc.RecordID) AND
    rc.Type = ''Create'' AND
    rc.EntityID = {{ EntityID | sqlString }}
WHERE
    rc.RecordID IS NULL
ORDER BY
    {{ PrimaryKeyOrderBy }}
'
SET
  @ID_0e930e55 = 'D85DE0AD-5B5B-4EF4-82BC-C634CE39E836' EXEC [${flyway:defaultSchema}].spUpdateQuerySQL @QueryID = @QueryID_0e930e55,
  @SQLDialectID = @SQLDialectID_0e930e55,
  @SQL = @SQL_0e930e55,
  @ID = @ID_0e930e55;

-- Save MJ: Query SQLs (core SP call only)
DECLARE @QueryID_8f8933eb UNIQUEIDENTIFIER,
@SQLDialectID_8f8933eb UNIQUEIDENTIFIER,
@SQL_8f8933eb NVARCHAR(MAX),
@ID_8f8933eb UNIQUEIDENTIFIER
SET
  @QueryID_8f8933eb = '46A91235-2122-40E8-9289-20D04489CAC5'
SET
  @SQLDialectID_8f8933eb = '426915F2-D4FE-4AB9-97A8-39063561DE9F'
SET
  @SQL_8f8933eb = N'-- PostgreSQL variant for External Change Detection - Detect Updates
SELECT
    ot.*, ot."{{ UpdatedAtField }}" AS "__ecd_UpdatedAt", rc.last_change_time AS "__ecd_LatestRecordChangeAt"
FROM
    "{{ SchemaName }}"."{{ BaseView }}" ot
INNER JOIN (
    SELECT
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM
        ${flyway:defaultSchema}.vwRecordChanges
    WHERE
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc.RecordID
WHERE
    ot."{{ UpdatedAtField }}" > COALESCE(rc.last_change_time, CAST(''1900-01-01 00:00:00.000'' AS TIMESTAMPTZ))
ORDER BY
    {{ PrimaryKeyOrderBy }}
'
SET
  @ID_8f8933eb = '565C5AF3-5F59-4531-B21D-53EBC884EF5B' EXEC [${flyway:defaultSchema}].spUpdateQuerySQL @QueryID = @QueryID_8f8933eb,
  @SQLDialectID = @SQLDialectID_8f8933eb,
  @SQL = @SQL_8f8933eb,
  @ID = @ID_8f8933eb;

GO

